// Calcula aged_ymd = today - 5d (mismo umbral que el KPI '+5 días')
const now = new Date();
const todayYMD = now.toLocaleDateString('en-CA', { timeZone:'Europe/Madrid' });
const d = new Date(todayYMD + 'T00:00:00Z'); d.setUTCDate(d.getUTCDate() - 5);
const agedYMD = d.toISOString().substring(0,10);
return [{ json: { today_ymd: todayYMD, aged_ymd: agedYMD } }];

// Construye el Set de IDs Zendesk aged abiertos
const tickets = $input.all().map(i => i.json).filter(Boolean);
const zdIds = new Set(tickets.map(t => String(t.id)).filter(Boolean));
return [{ json: { _zd_open_ids: [...zdIds], _zd_open_total: zdIds.size, _zd_tickets: tickets } }];

// Pre-extract zendesk_id desde NAME o HTML_NOTES de TODAS las tareas
// (igual que en sync-check)
const tasks = $input.all().map(i => i.json).filter(Boolean);
const cutoff = Date.now() - 365 * 86400000;

function findZdId(s) {
  if (!s) return null;
  const m = String(s).match(/#\s*(\d{2,7})/);
  return m ? m[1] : null;
}

const out = [];
for (const t of tasks) {
  if (!t) continue;
  if (t.completed === true && t.completed_at) {
    if (new Date(t.completed_at).getTime() < cutoff) continue;
  }
  const zdId = findZdId(t.name) || findZdId(t.html_notes);
  out.push({ ...t, _zd_id: zdId || null });
}
return out.map(t => ({ json: t }));

// Cruza los Zendesk aged contra Asana. Clasifica cada Zendesk ID
// (los 37) en 3 categorías exclusivas.
const tasks = $('Todas + Pre-extract').all().map(i => i.json);
const attResults = $input.all().map(i => i.json);
const zdData = $('Save ZD Aged').first().json;
const zdOpenIds = (zdData._zd_open_ids || []).map(String);
const zdTickets = zdData._zd_tickets || [];
const zdInfoById = new Map(zdTickets.map(t => [String(t.id), t]));

let srcName = 0, srcAtt = 0;
const byZdId = new Map();

for (let i = 0; i < tasks.length; i++) {
  const task = tasks[i];
  let zdId = task._zd_id || null;
  if (zdId) {
    srcName++;
  } else {
    const attResp = attResults[i] || {};
    const atts = Array.isArray(attResp.data) ? attResp.data : [];
    for (const att of atts) {
      const name = att && att.name ? String(att.name) : '';
      const m = name.match(/#\s*(\d{2,7})/);
      if (m) { zdId = m[1]; srcAtt++; break; }
    }
  }
  if (!zdId) continue;
  const existing = byZdId.get(String(zdId));
  if (!existing || (task.completed && !existing.completed)) {
    byZdId.set(String(zdId), task);
  }
}

const zd_completed = [];
const zd_in_progress = [];
const zd_no_asana = [];

function ageDays(createdAt){
  if (!createdAt) return null;
  return Math.floor((Date.now() - new Date(createdAt).getTime()) / 86400000);
}

for (const zdIdStr of zdOpenIds) {
  const t = byZdId.get(zdIdStr);
  const zdId = parseInt(zdIdStr, 10);
  const zdInfo = zdInfoById.get(zdIdStr) || {};
  const base = {
    zendesk_id: zdId,
    zendesk_subject: zdInfo.subject || '',
    zendesk_status: zdInfo.status || '',
    zendesk_age_days: ageDays(zdInfo.created_at),
    zendesk_url: `https://soporteyurest.zendesk.com/agent/tickets/${zdId}`
  };
  if (!t) {
    zd_no_asana.push(base);
  } else if (t.completed === true) {
    zd_completed.push({
      ...base,
      asana_gid: t.gid,
      asana_name: t.name,
      asana_url: t.permalink_url,
      asana_completed_at: t.completed_at
    });
  } else {
    zd_in_progress.push({
      ...base,
      asana_gid: t.gid,
      asana_name: t.name,
      asana_url: t.permalink_url
    });
  }
}

zd_completed.sort((a,b) => (b.asana_completed_at || '').localeCompare(a.asana_completed_at || ''));
zd_no_asana.sort((a,b) => (b.zendesk_age_days || 0) - (a.zendesk_age_days || 0));

return [{ json: {
  generated_at: new Date().toISOString(),
  zendesk_aged_total: zdOpenIds.length,
  asana_tasks_analyzed: tasks.length,
  resolved_from_name_notes: srcName,
  resolved_from_attachments: srcAtt,
  zd_completed_in_asana_count: zd_completed.length,
  zd_in_progress_count: zd_in_progress.length,
  zd_no_asana_count: zd_no_asana.length,
  zd_completed_in_asana_ids_csv: zd_completed.map(x => x.zendesk_id).join(','),
  zd_in_progress_ids_csv: zd_in_progress.map(x => x.zendesk_id).join(','),
  zd_no_asana_ids_csv: zd_no_asana.map(x => x.zendesk_id).join(','),
  zd_completed_in_asana: zd_completed,
  zd_in_progress: zd_in_progress,
  zd_no_asana: zd_no_asana
} }];
